templates.body:
$env:XAI_API_KEY = "paste-your-key-here"
$body = @{
  model = "grok-4.3"
  input = @(
    @{ role = "user"; content = "Reply with exactly: API works." }
  )
} | ConvertTo-Json -Depth 5

Invoke-RestMethod -Uri "https://api.x.ai/v1/responses" -Method POST -Headers @{
  "Authorization" = "Bearer $env:XAI_API_KEY"
  "Content-Type"  = "application/json"
} -Body $body
